example.code:
// Bad - floating promise
fetchData();

// Bad - missing await in async function
async function process() {
  saveToDb(data); // forgot await
}

// Bad - async event handler, rejection silently lost
button.addEventListener("click", async () => {
  await saveData(); // rejection unhandled
});

// Good - explicit error handling
button.addEventListener("click", () => {
  saveData().catch((err) => showError(err));
});

// Bad - race condition
let cache: Data | null = null;
async function getData(): Promise<Data> {
  if (!cache) {
    cache = await fetchData(); // two callers can both fetch
  }
  return cache;
}

// Bad - unnecessary wrapper
function fetchUser(id: string): Promise<User> {
  return new Promise((resolve, reject) => {
    fetch(`/api/users/${id}`)
      .then((res) => res.json())
      .then(resolve)
      .catch(reject);
  });
}
